class Solution(object):
    def replaceDigits(self, s):
        s_list = list(s)
        for i in range(1, len(s), 2):
            shift_amount = int(s[i])
            s_list[i] = chr(ord(s[i-1]) + shift_amount)
        return ''.join(s_list)
